}

public class EscapeCharacters {
    public static void main(String[] args) {
        // \n = new line
        System.out.println("First line\nSecond line\nThird line");

        System.out.println("---");

        // \t = tab (indentation)
        System.out.println("Name\tAge\tCity");
        System.out.println("Alice\t25\tLondon");
        System.out.println("Bob\t30\tParis");

        System.out.println("---");

        // \" = double quote inside string
        System.out.println("She said \"Hello!\" to everyone.");

        // \\ = literal backslash
        System.out.println("File path: C:\\Users\\Documents");
    }
}

public class StringJoining {
    public static void main(String[] args) {
        // Joining two strings
        String greeting = "Hello" + " " + "World";
        System.out.println(greeting);

        // Joining strings with numbers
        int year = 2025;
        System.out.println("The year is " + year);

        // The order trap!
        System.out.println("Sum: " + 5 + 3);    // Concatenation: 53
        System.out.println("Sum: " + (5 + 3));  // Math first: 8

        // Building a sentence
        String name = "Alice";
        int age = 25;
        String city = "London";
        System.out.println(name + " is " + age + " years old and lives in " + city + ".");
    }
}

public class FormattedOutput {
    public static void main(String[] args) {
        // Basic format specifiers
        String name = "Alice";
        int age = 25;
        double score = 95.678;

        System.out.printf("Name: %s%n", name);
        System.out.printf("Age: %d years%n", age);
        System.out.printf("Score: %.2f%%%n", score);  // .2f = 2 decimal places

        // Column formatting with width
        System.out.printf("%n%-15s %-5s %-10s%n", "NAME", "AGE", "CITY");
        System.out.printf("%-15s %-5d %-10s%n", "Alice", 25, "London");
        System.out.printf("%-15s %-5d %-10s%n", "Bob", 30, "Paris");
        System.out.printf("%-15s %-5d %-10s%n", "Charlie", 22, "Berlin");
    }
}

