/**
 * InvoiceGenerator - Creates a formatted invoice.
 * Real-world use of printf formatting and escape chars.
 */
public class InvoiceGenerator {
    public static void main(String[] args) {
        // Invoice data
        String company = "TechSupplies Ltd";
        String customer = "Alice Johnson";
        String invoiceNum = "INV-2025-0042";

        // Items
        String item1 = "Keyboard";
        double price1 = 49.99;
        int qty1 = 2;

        String item2 = "Mouse";
        double price2 = 29.95;
        int qty2 = 3;

        String item3 = "Monitor Stand";
        double price3 = 85.00;
        int qty3 = 1;

        // Calculate totals
        double total1 = price1 * qty1;
        double total2 = price2 * qty2;
        double total3 = price3 * qty3;
        double subtotal = total1 + total2 + total3;
        double tax = subtotal * 0.20;  // 20% VAT
        double grandTotal = subtotal + tax;

        // Print invoice
        System.out.println("============================================");
        System.out.printf("  INVOICE: %s%n", invoiceNum);
        System.out.printf("  From: %s%n", company);
        System.out.printf("  To:   %s%n", customer);
        System.out.println("============================================");
        System.out.printf("  %-20s %5s %8s %10s%n", "ITEM", "QTY", "PRICE", "TOTAL");
        System.out.println("  ------------------------------------------");
        System.out.printf("  %-20s %5d %8.2f %10.2f%n", item1, qty1, price1, total1);
        System.out.printf("  %-20s %5d %8.2f %10.2f%n", item2, qty2, price2, total2);
        System.out.printf("  %-20s %5d %8.2f %10.2f%n", item3, qty3, price3, total3);
        System.out.println("  ------------------------------------------");
        System.out.printf("  %36s %10.2f%n", "Subtotal:", subtotal);
        System.out.printf("  %36s %10.2f%n", "VAT (20%):", tax);
        System.out.println("  ==========================================");
        System.out.printf("  %36s %10.2f%n", "TOTAL DUE:", grandTotal);
        System.out.println("  ==========================================");
    }
}

